module top_module(clk, rst, npc, pc);input clk, rst;
  input [31:0] npc;
  output reg [31:0] pc;

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt)
  begin 
    if (rst == 1) pc <= 32'h0000_3000;
    else pc <= npc;
  end
endmodule
